/// Executor for DataExportRequest flow
pub struct DataExportRequestFlowExecutor<H: DataExportRequestStepHandler>(FlowExecutor<H>);

impl<H: DataExportRequestStepHandler + Send + Sync + 'static> DataExportRequestFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self(FlowExecutor::new(handler))
    }

    /// Start a new flow instance
    pub fn start(&self, instance_id: impl Into<String>) -> DataExportRequestFlowInstance {
        self.0.start(instance_id, DataExportRequestFlowStep::FetchRequest)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut DataExportRequestFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            DataExportRequestFlowStep::FetchRequest => {
                self.0.handler.handle_fetch_request(instance).await?
            }
            DataExportRequestFlowStep::ValidateRequest => {
                self.0.handler.handle_validate_request(instance).await?
            }
            DataExportRequestFlowStep::CheckAuthorization => {
                let next = self.0.handler.evaluate_check_authorization(instance).await?;
                Some(next)
            }
            DataExportRequestFlowStep::LogUnauthorized => {
                self.0.handler.handle_log_unauthorized(instance).await?
            }
            DataExportRequestFlowStep::UpdateStatusProcessing => {
                self.0.handler.handle_update_status_processing(instance).await?
            }
            DataExportRequestFlowStep::CollectUserData => {
                self.0.handler.handle_collect_user_data(instance).await?
            }
            DataExportRequestFlowStep::LogCollectionError => {
                self.0.handler.handle_log_collection_error(instance).await?
            }
            DataExportRequestFlowStep::GenerateExport => {
                self.0.handler.handle_generate_export(instance).await?
            }
            DataExportRequestFlowStep::LogGenerationError => {
                self.0.handler.handle_log_generation_error(instance).await?
            }
            DataExportRequestFlowStep::CalculateExpiry => {
                self.0.handler.handle_calculate_expiry(instance).await?
            }
            DataExportRequestFlowStep::UpdateCompleted => {
                self.0.handler.handle_update_completed(instance).await?
            }
            DataExportRequestFlowStep::LogCompletion => {
                self.0.handler.handle_log_completion(instance).await?
            }
            DataExportRequestFlowStep::SendNotification => {
                self.0.handler.handle_send_notification(instance).await?
            }
            DataExportRequestFlowStep::MarkFailed => {
                self.0.handler.handle_mark_failed(instance).await?
            }
            DataExportRequestFlowStep::Complete => {
                self.0.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            DataExportRequestFlowStep::WorkflowFailed => {
                self.0.handler.handle_workflow_failed(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = FlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut DataExportRequestFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != FlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut DataExportRequestFlowInstance) { self.0.cancel(instance) }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut DataExportRequestFlowInstance, error: impl Into<String>) { self.0.fail(instance, error) }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = DataExportRequestFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, FlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = DataExportRequestFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = DataExportRequestFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = FlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = FlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
